// 解析AI分析结果并准备数据库插入数据
const webhookData = $('接收小红书数据').first().json;
const aiAnalysisResult = $('AI创作者分析').first().json;

// 从 webhook body 中获取数据
const bodyData = webhookData.body || webhookData;

// 准备作者数据
const authorData = {
 user_name: bodyData.userName || '',
 user_xhs_id: bodyData.userId || '',
 subscribers: parseInt(bodyData.subscribers) || 0,
 followers: parseInt(bodyData.followers) || 0,
 likes: parseInt(bodyData.likes) || 0,
 profile_url: bodyData.profileUrl || '',
 report: aiAnalysisResult.output || aiAnalysisResult.text || JSON.stringify(aiAnalysisResult)
};

// 计算other_notes（allTitles中除了top10Notes标题外的其他标题）
const top10Titles = bodyData.top10Notes ? bodyData.top10Notes.map(note => note.title) : [];
const otherTitles = bodyData.allTitles ? bodyData.allTitles.filter(title => !top10Titles.includes(title)) : [];
authorData.other_notes = otherTitles;

// 准备笔记数据
const notesData = [];
if (bodyData.top10Notes && Array.isArray(bodyData.top10Notes)) {
 bodyData.top10Notes.forEach(note => {
 const noteData = {
 title: note.title,
 description: note.desc || '',
 likes: parseInt(note.like) || 0,
 collects: parseInt(note.collect) || 0,
 is_top10: true,
 raw_json: note
 };
 notesData.push(noteData);
 });
}

return [
 {
 json: {
 authorData: authorData,
 notesData: notesData,
 originalData: bodyData,
 analysisResult: aiAnalysisResult
 }
 }
];

// 为每个笔记数据添加author_id
const authorId = $('保存作者数据').first().json.id;
const notesData = $('数据处理器').first().json.notesData;

// 为每个笔记添加author_id
const processedNotes = notesData.map(note => ({
 ...note,
 author_id: authorId
}));

return processedNotes.map(note => ({ json: note }));

// 检查所有数据是否保存成功并返回结果
const authorResult = $('保存作者数据').first();
const notesResults = $('保存笔记数据').all();

let success = true;
let message = '数据保存成功';
let details = {
 authorSaved: false,
 notesSaved: 0,
 totalNotes: 0
};

try {
 // 检查作者数据是否保存成功
 if (authorResult && authorResult.json && authorResult.json.id) {
 details.authorSaved = true;
 } else {
 success = false;
 message = '作者数据保存失败';
 }

 // 检查笔记数据是否保存成功
 details.totalNotes = notesResults.length;
 details.notesSaved = notesResults.filter(result => result.json && result.json.id).length;

 if (details.notesSaved !== details.totalNotes) {
 success = false;
 message = `部分笔记数据保存失败，成功保存 ${details.notesSaved}/${details.totalNotes}`;
 }

} catch (error) {
 success = false;
 message = '数据处理过程中发生错误: ' + error.message;
}

return [{
 json: {
 success: success,
 message: message,
 details: details,
 authorId: authorResult?.json?.id || null,
 timestamp: new Date().toISOString()
 }
}];
